VALUES
  ('public-health-specialist-moex-00287', 'public-health-specialist', 'public-health-specialist-moex-113-50d43abc', 'sub-public-health-specialist-03', NULL, 'single_choice', '職場社會心理危害保護漸受國內外職業衛生領域之重視，目前對於工作者的工作條件與身心 健康之保護介入措施可分為三級，主要目的在於解決與工作環境有關的問題或壓力來源，下 列何者不屬於職場社會心理危害初級的職場介入措施？', '["制定組織政策與程序", "壓力與過勞評估，以瞭解員工工作現況", "工作設計與工作量管理", "改善控制及訓練"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "16918ff39647", "answer_pdf_sha1": "76106db6fc46", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0805", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "環境與職業衛生", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00288', 'public-health-specialist', 'public-health-specialist-moex-113-50d43abc', 'sub-public-health-specialist-03', NULL, 'single_choice', '某勞工在A場地停留工作兩小時，使用溶劑是X（溶劑TLV-TW為100ppm，實際監測值30ppm）， 在B場地也是工作停留兩小時，溶劑是Y（溶劑TLV-TW為50ppm，實際監測值10ppm），中午 休息一小時，下午繼續工作，下午工作（四小時）都在C場地，溶劑是Z（溶劑TLV-TW為60ppm， 實際監測值30ppm），假設各溶劑之毒性作用為獨立且未有相乘作用，該勞工是否具備有機溶劑 暴露造成健康上之疑慮？', '["未超出許可標準，符合健康風險估算要求", "超出可容許暴露標準，須立即採取工程或行政管制作為", "超出可容許暴露標準10%，可藉由中午休息時間彈性增加一小時，即可達成可接受暴露標準", "剛好符合可接受暴露標準，需定期監測與複查"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "16918ff39647", "answer_pdf_sha1": "76106db6fc46", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0805", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "環境與職業衛生", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00289', 'public-health-specialist', 'public-health-specialist-moex-113-50d43abc', 'sub-public-health-specialist-03', NULL, 'single_choice', '下列關於噪音的敘述何者錯誤？', '["只要是能讓人聽了感到不舒服的聲音，都可以視為廣義的噪音", "一般對噪音的認定方式以音量大小為主，音量過高時即認定為噪音", "噪音對健康的影響以聽力損失為主，但也可能造成其他生理及心理的影響", "人耳對不同頻率的聲音反應不盡相同，一般人僅對2,000～20,000Hz的聲音有聽覺反應"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "16918ff39647", "answer_pdf_sha1": "76106db6fc46", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0805", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "環境與職業衛生", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00290', 'public-health-specialist', 'public-health-specialist-moex-113-50d43abc', 'sub-public-health-specialist-03', NULL, 'single_choice', '下列關於廢棄物分類的敘述何者錯誤？', '["固體廢棄物係以固體為主，液體含量以不足以自由流動為原則", "一般而言，廢棄物的認定以固體及液體為主，且排除生活污水及工業廢水等以水為主的廢棄物", "事業單位產生之廢棄物，若不具有害事業廢棄物認定的成分或特性，則可自行認定為一般 事業廢棄物", "有害事業廢棄物是依照廢棄物的成分及指定有害特性予以認定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "16918ff39647", "answer_pdf_sha1": "76106db6fc46", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0805", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "環境與職業衛生", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00291', 'public-health-specialist', 'public-health-specialist-moex-113-50d43abc', 'sub-public-health-specialist-03', NULL, 'single_choice', '下列關於食品安全之敘述何者錯誤？', '["食品製備的過程中應注重器具及環境清潔，以免污染食物", "生食與熟食應分開處理，以免交互污染", "食物應保持在安全的溫度下，以免微生物孳生", "食品大多有保存期限，但只要保存狀況良好仍可使用"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "16918ff39647", "answer_pdf_sha1": "76106db6fc46", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0805", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "環境與職業衛生", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00292', 'public-health-specialist', 'public-health-specialist-moex-113-50d43abc', 'sub-public-health-specialist-03', NULL, 'single_choice', '為避免飲用水微生物孳生，淨水處理過程中通常會加氯消毒，但容易衍生消毒副產物。下列 何者不是消毒副產物？', '["氯酚", "三氯甲烷", "一溴二氯甲烷", "二溴一氯甲烷"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "16918ff39647", "answer_pdf_sha1": "76106db6fc46", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0805", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "環境與職業衛生", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00293', 'public-health-specialist', 'public-health-specialist-moex-113-50d43abc', 'sub-public-health-specialist-03', NULL, 'single_choice', '單一有毒物質造成的人體危害反應，有時可能因為不同暴露途徑而有差別，造成危害反應差 別的原因可能來自下列何者？', '["吸收效率", "代謝途徑", "排泄機制", "標的器官"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "16918ff39647", "answer_pdf_sha1": "76106db6fc46", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0805", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "環境與職業衛生", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00294', 'public-health-specialist', 'public-health-specialist-moex-113-50d43abc', 'sub-public-health-specialist-03', NULL, 'single_choice', '下列關於毒性化學物質列管認定方式的說明何者正確？', '["依照主要化學成分、濃度含量、現場運作量大小判定是否列管", "依照主要化學成分、濃度含量、每年總運作量大小判定是否列管", "依照主要化學成分、濃度含量、以往事故紀錄判定是否列管", "依照主要化學成分、濃度含量判定是否列管"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "16918ff39647", "answer_pdf_sha1": "76106db6fc46", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0805", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "環境與職業衛生", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00295', 'public-health-specialist', 'public-health-specialist-moex-113-50d43abc', 'sub-public-health-specialist-03', NULL, 'single_choice', '下列關於毒性化學物質管理的敘述何者正確？', '["目前列管的毒性化學物質，依主要危害特性分為六大類", "運作列管毒性化學物質的事業單位，皆須設置專責人員，並定期申報運作紀錄", "列管之毒性化學物質，中央主管機關得公告限制或禁止其有關之運作", "毒性化學物質僅限人為產製的化學品，非刻意製造或自然存在的物質不在此限"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "16918ff39647", "answer_pdf_sha1": "76106db6fc46", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0805", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "環境與職業衛生", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00296', 'public-health-specialist', 'public-health-specialist-moex-113-50d43abc', 'sub-public-health-specialist-03', NULL, 'single_choice', '下列關於環境影響評估之敘述何者正確？', '["環境影響評估僅適用於環境開發行為", "環境影響評估的範圍僅針對生活環境及自然生態環境的潛在影響", "開發單位透過環境影響評估說明書，說明開發行為可能產生的環境影響，並針對預期的影 響提出控制改善的策略", "環境影響評估固定分兩階段進行，第一階段環境影響說明書，第二階段才須實際進行環境 影響評估"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "16918ff39647", "answer_pdf_sha1": "76106db6fc46", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0805", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "環境與職業衛生", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL)
